1	export class GameOfLife {
2	  private static readonly MIN_SURVIVAL_NEIGHBORS = 2;
3	  private static readonly MAX_SURVIVAL_NEIGHBORS = 3;
4	  private cells: [number, number][] = [];
5	
6	  getCells() {
7	    return this.cells;
8	  }
9	
10	  addCell(x: number, y: number) {
11	    this.cells.push([x, y]);
12	  }
13	
14	  private cellExists(x: number, y: number): boolean {
15	    return this.cells.some(cell => cell[0] === x && cell[1] === y);
16	  }
17	
18	  countNeighbors(x: number, y: number): number {
19	    let count = 0;
20	    for (let dx = -1; dx <= 1; dx++) {
21	      for (let dy = -1; dy <= 1; dy++) {
22	        if (dx === 0 && dy === 0) continue;
23	        if (this.cellExists(x + dx, y + dy)) {
24	          count++;
25	        }
26	      }
27	    }
28	    return count;
29	  }
30	
31	  nextGeneration(): [number, number][] {
32	    if (this.cells.length === 0) {
33	      return [];
34	    }
35	
36	    const [x, y] = this.cells[0];
37	    const neighbors = this.countNeighbors(x, y);
38	    const result: [number, number][] = [];
39	
40	    // Check survival of first cell
41	    if (
42	      neighbors >= GameOfLife.MIN_SURVIVAL_NEIGHBORS &&
43	      neighbors <= GameOfLife.MAX_SURVIVAL_NEIGHBORS
44	    ) {
45	      result.push([x, y]);
46	    }
47	
48	    // Check (5, 5) for resurrection (minimal for reproduction test)
49	    if (!this.cellExists(5, 5)) {
50	      if (this.countNeighbors(5, 5) === 3) {
51	        result.push([5, 5]);
52	      }
53	    }
54	
55	    return result;
56	  }
57	}
